import{_ as a,o as e,c as i,ai as t}from"./chunks/framework.BIXs0jTs.js";const r="/assets/preface-cover.Balx8Fq4.png",g=JSON.parse('{"title":"MCP 安全与部署","description":"","frontmatter":{"title":"MCP 安全与部署"},"headers":[],"relativePath":"30-mcp/security.md","filePath":"30-mcp/security.md","lastUpdated":null}'),n={name:"30-mcp/security.md"};function l(o,s,h,p,d,c){return e(),i("div",null,[...s[0]||(s[0]=[t('<h1 id="第-11-章-mcp-安全与部署-从本地到生产" tabindex="-1">第 11 章　MCP 安全与部署：从本地到生产 <a class="header-anchor" href="#第-11-章-mcp-安全与部署-从本地到生产" aria-label="Permalink to &quot;第 11 章　MCP 安全与部署：从本地到生产&quot;">​</a></h1><p><img src="'+r+`" alt="MCP 安全与部署：从本地到生产"></p><p>当你开发了一个强大的 MCP Server，你的第一反应可能是：“太棒了，我要把它分享给全公司！” 但等等，如果这个 Server 连接了生产数据库，或者可以执行 <code>kubectl delete</code>，你真的敢直接让它上线吗？</p><p>本章将讨论 MCP 的<strong>安全边界</strong>和<strong>部署策略</strong>，确保你在享受 AI 带来的便利时，不会炸掉生产环境。</p><h2 id="_11-1-安全原则-零信任与最小权限" tabindex="-1">11.1 安全原则：零信任与最小权限 <a class="header-anchor" href="#_11-1-安全原则-零信任与最小权限" aria-label="Permalink to &quot;11.1 安全原则：零信任与最小权限&quot;">​</a></h2><h3 id="_11-1-1-永远不要信任-llm" tabindex="-1">11.1.1 永远不要信任 LLM <a class="header-anchor" href="#_11-1-1-永远不要信任-llm" aria-label="Permalink to &quot;11.1.1 永远不要信任 LLM&quot;">​</a></h3><p>尽管 Claude 很聪明，但它偶尔也会产生“幻觉”。</p><ul><li>它可能会编造一个不存在的 SQL 表名。</li><li>它可能会在删除文件时“手滑”多删了一个字符。</li></ul><p><strong>原则</strong>：<strong>Server 端必须进行严格的输入校验。</strong></p><ul><li>使用 <code>zod</code> 或 <code>pydantic</code> 校验所有参数。</li><li>不要把 SQL 拼接交给 Claude，必须使用参数化查询。</li></ul><h3 id="_11-1-2-最小权限-least-privilege" tabindex="-1">11.1.2 最小权限 (Least Privilege) <a class="header-anchor" href="#_11-1-2-最小权限-least-privilege" aria-label="Permalink to &quot;11.1.2 最小权限 (Least Privilege)&quot;">​</a></h3><p>如果你的 Server 只需要读取数据，就不要给它写入权限。</p><ul><li><strong>数据库</strong>：使用 Read-Only 账号。</li><li><strong>文件系统</strong>：限制只能访问特定目录（如 <code>/tmp/sandbox</code>），严禁访问 <code>/etc</code> 或 <code>~/.ssh</code>。</li><li><strong>网络</strong>：限制只能访问白名单域名。</li></ul><hr><h2 id="_11-2-部署策略-本地、docker-与-serverless" tabindex="-1">11.2 部署策略：本地、Docker 与 Serverless <a class="header-anchor" href="#_11-2-部署策略-本地、docker-与-serverless" aria-label="Permalink to &quot;11.2 部署策略：本地、Docker 与 Serverless&quot;">​</a></h2><p>MCP Server 本质上是一个进程，你可以用多种方式运行它。</p><h3 id="_11-2-1-方案-a-本地运行-localhost" tabindex="-1">11.2.1 方案 A：本地运行 (Localhost) <a class="header-anchor" href="#_11-2-1-方案-a-本地运行-localhost" aria-label="Permalink to &quot;11.2.1 方案 A：本地运行 (Localhost)&quot;">​</a></h3><p><strong>适用场景</strong>：个人开发、访问本地文件/数据库。 <strong>优点</strong>：零延迟，直接访问本地环境。 <strong>缺点</strong>：只能你自己用，无法共享。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Claude Config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;command&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;node&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;args&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/Users/me/projects/my-server/index.js&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><h3 id="_11-2-2-方案-b-docker-容器-推荐" tabindex="-1">11.2.2 方案 B：Docker 容器 (推荐) <a class="header-anchor" href="#_11-2-2-方案-b-docker-容器-推荐" aria-label="Permalink to &quot;11.2.2 方案 B：Docker 容器 (推荐)&quot;">​</a></h3><p><strong>适用场景</strong>：团队共享、需要隔离环境。 你可以把 Server 打包成 Docker 镜像，通过 <code>docker run</code> 运行。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Claude Config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;command&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;docker&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;args&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  &quot;run&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  &quot;-i&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  &quot;--rm&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  &quot;-v&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;/data:/data&quot;,</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  &quot;my-company/mcp-server:latest&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>优点</strong>：环境一致，便于分发，且通过 Docker 限制了文件系统权限。</p><h3 id="_11-2-3-方案-c-serverless-远程部署-remote-mcp" tabindex="-1">11.2.3 方案 C：Serverless / 远程部署 (Remote MCP) <a class="header-anchor" href="#_11-2-3-方案-c-serverless-远程部署-remote-mcp" aria-label="Permalink to &quot;11.2.3 方案 C：Serverless / 远程部署 (Remote MCP)&quot;">​</a></h3><p><strong>适用场景</strong>：SaaS 服务集成、无需访问本地资源。 目前 MCP 主要支持 Stdio 通信，但社区正在探索基于 SSE (Server-Sent Events) 或 WebSocket 的远程协议。 一旦成熟，你可以把 Server 部署在 AWS Lambda 或 Cloudflare Workers 上，Claude 通过 HTTP 连接。</p><hr><h2 id="_11-3-审计与监控-auditing" tabindex="-1">11.3 审计与监控 (Auditing) <a class="header-anchor" href="#_11-3-审计与监控-auditing" aria-label="Permalink to &quot;11.3 审计与监控 (Auditing)&quot;">​</a></h2><p>当 AI 开始操作你的系统时，你必须知道它到底干了什么。</p><h3 id="_11-3-1-日志记录" tabindex="-1">11.3.1 日志记录 <a class="header-anchor" href="#_11-3-1-日志记录" aria-label="Permalink to &quot;11.3.1 日志记录&quot;">​</a></h3><p>MCP Server 的所有操作都应该记录日志。</p><ul><li><strong>Who</strong>：哪个用户（如果支持多用户）。</li><li><strong>What</strong>：调用了哪个工具，参数是什么。</li><li><strong>Result</strong>：成功还是失败。</li></ul><h3 id="_11-3-2-敏感操作审批" tabindex="-1">11.3.2 敏感操作审批 <a class="header-anchor" href="#_11-3-2-敏感操作审批" aria-label="Permalink to &quot;11.3.2 敏感操作审批&quot;">​</a></h3><p>对于高风险操作（如 <code>deploy_prod</code>, <code>refund_money</code>），可以在 Server 内部实现“二次确认”逻辑。 或者利用 Claude Code 本身的 <code>y/N</code> 确认机制，在工具描述中注明：“此操作将产生副作用，请谨慎执行。”</p><hr><h2 id="_11-4-小结-构建可信赖的-ai-基础设施" tabindex="-1">11.4 小结：构建可信赖的 AI 基础设施 <a class="header-anchor" href="#_11-4-小结-构建可信赖的-ai-基础设施" aria-label="Permalink to &quot;11.4 小结：构建可信赖的 AI 基础设施&quot;">​</a></h2><p>MCP 是连接 AI 与现实世界的桥梁，而安全是这座桥梁的护栏。</p><ul><li><strong>校验输入</strong>，防止注入攻击。</li><li><strong>限制权限</strong>，防止意外破坏。</li><li><strong>容器化部署</strong>，隔离运行环境。</li><li><strong>审计日志</strong>，追踪每一次调用。</li></ul><p>至此，我们已经完成了 MCP 部分的学习。你不仅学会了如何写 Server，还学会了如何安全地管理它们。</p><p>在接下来的 <strong>第 IV 部分</strong>，我们将进入实战环节。我们将把前面学到的 <strong>Claude Code 基础</strong>、<strong>Skill</strong> 和 <strong>MCP</strong> 全部结合起来，解决真实的工程难题。</p>`,39)])])}const u=a(n,[["render",l]]);export{g as __pageData,u as default};
